import{_ as i,o as a,c as t,a2 as s}from"./chunks/framework.BWuWLRhz.js";const h=JSON.parse('{"title":"Public plugin page routes","description":"","frontmatter":{"rfc":34,"title":"Public plugin page routes","status":"Draft","date":"June 2026","author":"kasunben","scope":"packages/manifest, runtime middleware, runtime route guard, docs; builds on PLT-16 public API delegation and RFC 0024\\n","incorporated_into_plan":"No — documentation-first. This RFC specifies a manifest-declared public page route primitive for plugins; scheduling and task IDs are deferred."},"headers":[],"relativePath":"rfcs/0042-public-plugin-routes.md","filePath":"rfcs/0042-public-plugin-routes.md"}'),l={name:"rfcs/0042-public-plugin-routes.md"};function o(n,e,r,u,d,p){return a(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="rfc-0042-—-public-plugin-page-routes" tabindex="-1">RFC 0042 — Public Plugin Page Routes <a class="header-anchor" href="#rfc-0042-—-public-plugin-page-routes" aria-label="Permalink to &quot;RFC 0042 — Public Plugin Page Routes&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Add a manifest-declared way for a plugin to expose specific page routes without the global session redirect. These routes are public entry points where the plugin owns authentication and authorization, usually through an expiring token, a public identifier, or a session fallback.</p><p>This extends the same principle as public <code>/api/*</code> delegation: the platform can exempt a narrow, declared route from the session gate, but the plugin must then perform its own access check and fail closed.</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>Some plugins need read-only public pages: a shared document, a public board, a published view, or a token-protected preview. Today the runtime session-gates page routes. A plugin can expose public API endpoints through <code>/api/*</code> if it is the single API provider, but there is no equivalent for public pages.</p><p>Without a public-page primitive, plugins either cannot implement public sharing, link users to an external system, or try to smuggle HTML through API routes. A small manifest feature keeps public exposure explicit and reviewable.</p><h2 id="current-state" tabindex="-1">Current state <a class="header-anchor" href="#current-state" aria-label="Permalink to &quot;Current state&quot;">​</a></h2><ul><li>Runtime middleware redirects unauthenticated page requests to <code>/login</code>.</li><li><code>apiProvider: true</code> allows one plugin to own public <code>/api/&lt;slug&gt;/*</code>.</li><li>Public API delegation is path-based and plugin-owned for auth.</li><li>There is no manifest field for public page routes.</li></ul><h2 id="proposed-design" tabindex="-1">Proposed design <a class="header-anchor" href="#proposed-design" aria-label="Permalink to &quot;Proposed design&quot;">​</a></h2><h3 id="manifest-field" tabindex="-1">Manifest field <a class="header-anchor" href="#manifest-field" aria-label="Permalink to &quot;Manifest field&quot;">​</a></h3><p>Add optional <code>publicRoutes</code> to <code>manifest.json</code>:</p><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;publicRoutes&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;prefix&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/p&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;description&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Token-protected public read-only pages.&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ],</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Rules:</p><ul><li><code>prefix</code> is relative to the plugin <code>routePrefix</code>.</li><li>It must start with <code>/</code>.</li><li>It must not be <code>/</code>.</li><li>It must not contain route groups or interception markers.</li><li>It must resolve under the plugin route prefix only.</li><li>Public routes are never inherited by child plugins or API routes.</li></ul><p>Example resolution:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>routePrefix: /example</span></span>
<span class="line"><span>publicRoutes[0].prefix: /p</span></span>
<span class="line"><span>exempt path: /example/p/*</span></span></code></pre></div><h3 id="middleware-behavior" tabindex="-1">Middleware behavior <a class="header-anchor" href="#middleware-behavior" aria-label="Permalink to &quot;Middleware behavior&quot;">​</a></h3><p>For a request under a public plugin route:</p><ol><li>Middleware still applies CSP and security headers.</li><li>Middleware does not redirect unauthenticated users to <code>/login</code>.</li><li>Middleware injects session headers if a valid session exists.</li><li>Middleware omits session headers if no valid session exists.</li><li>The plugin page renders and must perform token/session authorization itself.</li></ol><p>Disabled-plugin and paywall gates still apply. A disabled plugin&#39;s public route returns 404. A paywalled plugin&#39;s public route behavior is an open question; the default should be to block unless the public route is explicitly marked <code>paywallExempt</code>.</p><h3 id="plugin-responsibility" tabindex="-1">Plugin responsibility <a class="header-anchor" href="#plugin-responsibility" aria-label="Permalink to &quot;Plugin responsibility&quot;">​</a></h3><p>A public route must:</p><ul><li>validate its token or public identifier server-side;</li><li>return 404 for invalid, expired, disabled, or unknown shares;</li><li>avoid leaking whether a private resource exists;</li><li>render read-only by default;</li><li>use a session fallback only when the session user has normal plugin access to the underlying resource.</li></ul><h3 id="token-storage" tabindex="-1">Token storage <a class="header-anchor" href="#token-storage" aria-label="Permalink to &quot;Token storage&quot;">​</a></h3><p>This RFC does not define token tables. Each plugin owns its public-share model. Recommended fields:</p><ul><li>token hash, not plaintext token;</li><li>resource ID;</li><li>created by;</li><li>created at;</li><li>expires at;</li><li>revoked at;</li><li>mode (<code>expiring</code>, <code>permanent</code>, or plugin-specific enum).</li></ul><h2 id="security-requirements" tabindex="-1">Security requirements <a class="header-anchor" href="#security-requirements" aria-label="Permalink to &quot;Security requirements&quot;">​</a></h2><ul><li>Public route declarations are validated at build/install time.</li><li>Public route prefixes cannot overlap another plugin&#39;s route prefix.</li><li>Public routes cannot point at runtime routes.</li><li>Invalid public links return 404, not 401/403.</li><li>Public pages must not expose mutation controls to unauthenticated users.</li><li>Public routes are listed in Console health/plugin detail views.</li></ul><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><h3 id="use-public-api-routes-to-serve-html" tabindex="-1">Use public <code>/api/*</code> routes to serve HTML <a class="header-anchor" href="#use-public-api-routes-to-serve-html" aria-label="Permalink to &quot;Use public \`/api/*\` routes to serve HTML&quot;">​</a></h3><p>Rejected. API routes are for machine-readable endpoints and only support one provider plugin per instance. Public pages need plugin-local ownership and normal rendering.</p><h3 id="make-all-plugin-routes-optionally-public-at-runtime" tabindex="-1">Make all plugin routes optionally public at runtime <a class="header-anchor" href="#make-all-plugin-routes-optionally-public-at-runtime" aria-label="Permalink to &quot;Make all plugin routes optionally public at runtime&quot;">​</a></h3><p>Rejected. Public exposure must be explicit in the manifest so install/build review can catch it.</p><h3 id="add-a-platform-wide-public-share-service" tabindex="-1">Add a platform-wide public share service <a class="header-anchor" href="#add-a-platform-wide-public-share-service" aria-label="Permalink to &quot;Add a platform-wide public share service&quot;">​</a></h3><p>Deferred. Plugins have different resource models. A generic public-route primitive is smaller and keeps authorization near the resource owner.</p><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ol><li>Should <code>publicRoutes</code> support <code>paywallExempt</code>, or should monetized plugins be blocked from public pages unless a separate RFC defines sharing and entitlements?</li><li>Should public routes be eligible for root-plugin rewrite?</li><li>Should public routes support cache hints in the manifest?</li><li>Should Console show a consolidated list of active public shares, or only the route declarations?</li></ol><h2 id="adoption-path" tabindex="-1">Adoption path <a class="header-anchor" href="#adoption-path" aria-label="Permalink to &quot;Adoption path&quot;">​</a></h2><ol><li>Add <code>publicRoutes</code> to the manifest schema.</li><li>Add validation for route-prefix safety.</li><li>Extend middleware route decisions to skip login redirects for declared public route prefixes.</li><li>Add tests for authenticated, unauthenticated, disabled-plugin, and invalid route cases.</li><li>Document public-route implementation patterns.</li></ol><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Change</th></tr></thead><tbody><tr><td>0.1</td><td>June 2026</td><td>Initial draft</td></tr></tbody></table>`,42)])])}const b=i(l,[["render",o]]);export{h as __pageData,b as default};
